313→@Composable
314→fun DictationPanel(
315→    subtitle: SubtitleCue?,
316→    onSpeak: (String) -> Unit,
317→    onNext: () -> Unit,
318→    onLookup: (String) -> Unit
319→) {
320→    if (subtitle == null) {
321→        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
322→            Text("没有字幕可用", color = MaterialTheme.colorScheme.onSurfaceVariant)
323→        }
324→        return
325→    }
326→
327→    val words = subtitle.text.split(Regex("\\s+")).filter { it.isNotBlank() }
328→    val answers = remember(subtitle) { words.map { it.replace(Regex("[^\\p{L}\\p{M}'-]"), "") } }
329→    val inputs = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
330→    val results = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
331→
332→    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
333→        // Word input boxes
334→        Card(modifier = Modifier.fillMaxWidth()) {
335→            Column(modifier = Modifier.padding(16.dp)) {
336→                Row(
337→                    modifier = Modifier.fillMaxWidth(),
338→                    horizontalArrangement = Arrangement.spacedBy(8.dp),
339→                    verticalAlignment = Alignment.CenterVertically
340→                ) {
341→                    words.forEachIndexed { i, word ->
342→                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
343→                            OutlinedTextField(
344→                                value = inputs[i],
345→                                onValueChange = { inputs[i] = it },
346→                                modifier = Modifier.width((word.length * 14 + 30).coerceAtLeast(60).dp),
347→                                singleLine = true,
348→                                isError = results[i] == "wrong",
349→                                colors = OutlinedTextFieldDefaults.colors(
350→                                    focusedBorderColor = if (results[i] == "correct") Color.Green else MaterialTheme.colorScheme.primary
351→                                )
352→                            )
353→                            if (results[i] == "wrong") {
354→                                Text(answers[i], color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.labelSmall)
355→                            }
356→                            TextButton(onClick = { onLookup(word.replace(Regex("[^\\p{L}\\p{M}'-]"), "")) }) {
357→                                Text("查词", style = MaterialTheme.typography.labelSmall)
358→                            }
359→                        }
360→                    }
361→                }
362→            }
363→        }
364→
365→        Spacer(Modifier.height(12.dp))
366→
367→        // Control buttons
368→        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
369→            Button(onClick = { onSpeak(subtitle.text) }) {
370→                Icon(Icons.Default.VolumeUp, null, Modifier.size(16.dp))
371→                Spacer(Modifier.width(4.dp))
372→                Text("朗读")
373→            }
374→            Button(onClick = {
375→                answers.forEachIndexed { i, answer ->
376→                    results[i] = if (inputs[i].trim().equals(answer, ignoreCase = true)) "correct" else "wrong"
377→                }
378→            }) {
379→                Icon(Icons.Default.Check, null, Modifier.size(16.dp))
380→                Spacer(Modifier.width(4.dp))
381→                Text("检查")
382→            }
383→            Button(onClick = {
384→                inputs.indices.forEach { inputs[it] = "" }
385→                results.indices.forEach { results[it] = "" }
386→                onNext()
387→            }) {
388→                Icon(Icons.Default.ArrowForward, null, Modifier.size(16.dp))
389→                Spacer(Modifier.width(4.dp))
390→                Text("下一句")
391→            }
392→        }
393→    }
394→}
395→
396→private fun formatTime(ms: Long): String {
397→    val totalSec = ms / 1000
398→    val m = totalSec / 60
399→    val s = totalSec % 60
400→    return "$m:${s.toString().padStart(2, '0')}"
401→}
